```ts web/breeze/components/CalcPage/hooks/useFetchedPackageSelection.ts
import { useEffect, useState } from 'react';
import useSWRImmutable from 'swr/immutable';
import {
  Cloud$Interest,
  Cloud$Package,
  Cloud$PackageVariantBattery,
} from '@otovo/shared/types/cloudApi';
import { PackageStateBattery } from '../../../stores/Interest/type';
import {
  getFinancingOption,
  isEvChargerPackage,
} from '../../../lib/packageUtils';

const fetchPackageVariants = async (url: string) => {
  const response = await fetch(url, {
    method: 'GET',
  });

  if (!response.ok) {
    throw new Error(response.statusText);
  }

  return response.json();
};

type UpdatePkgArgs = [string, Cloud$PackageVariantBattery];

async function fetchUpdatedPackage([url, packageParams]: UpdatePkgArgs) {
  const response = await fetch(url, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(packageParams),
  });

  if (!response.ok) {
    throw new Error('Failed to update package');
  }

  return response.json();
}

function createVariantFromPackage(pkg: Cloud$Package) {
  return {
    battery_package_size: pkg.package_size,
    main_hardware_type: 'battery_system' as const,
    with_ev_charger: isEvChargerPackage(pkg),
  };
}

export function useFetchedPackageSelection(
  interest: Cloud$Interest,
): PackageStateBattery {
  const initialVariant = {
    // Infer the initial package variant based on the active shopping cart package
    battery_package_size: interest.active_shopping_cart_package.package_size,
    main_hardware_type: 'battery_system' as const,
    with_ev_charger: isEvChargerPackage(interest.active_shopping_cart_package),
  };

  const [selectedVariant, setSelectedVariant] =
    useState<Cloud$PackageVariantBattery>(initialVariant);

  const [selectedFinancingOption, setSelectedFinancingOption] = useState(
    getFinancingOption(
      interest.active_shopping_cart_package?.price.financing_options,
      interest.default_purchase_model,
    ),
  );

  const { data: lazyFetchedVariants, isLoading: isLoadingLazyVariants } =
    useSWRImmutable<Cloud$PackageVariantBattery[]>(
      `${process.env.NEXT_PUBLIC_OTOVOAPI_URL}/web/interests/${interest.id}/package_options/?main_hardware_type=battery_system`,
      fetchPackageVariants,
    );

  const { data: remoteSelectedPackage, isLoading: isLoadingPackage } =
    useSWRImmutable<Cloud$Package>(
      [
        `${process.env.NEXT_PUBLIC_OTOVOAPI_URL}/web/interests/${interest.id}/update_package/`,
        selectedVariant, // Using selectedVariant as cache key
      ],
      fetchUpdatedPackage,
    );

  const selectedPackage =
    remoteSelectedPackage || interest.active_shopping_cart_package;

  useEffect(() => {
    setSelectedFinancingOption((prev) =>
      getFinancingOption(
        selectedPackage.price.financing_options,
        prev.purchase_model_code,
      ),
    );
  }, [selectedPackage]);

  const changePackage: PackageStateBattery['changePackage'] = async (
    pkgChange,
  ) => {
    const variant = createVariantFromPackage(selectedPackage);
    variant[pkgChange.option] = pkgChange.value;
    setSelectedVariant(variant);
  };

  const changePurchaseModel: PackageStateBattery['changePurchaseModel'] = (
    code,
  ) => {
    if (!selectedPackage) return;

    setSelectedFinancingOption(
      (prev) =>
        getFinancingOption(selectedPackage.price.financing_options, code) ||
        prev,
    );
  };

  const allVariants = [initialVariant, ...(lazyFetchedVariants || [])];

  return {
    selectedPackage: selectedPackage,
    selectedFinancingOption,
    availablePackageVariants: allVariants,
    isLoading: isLoadingLazyVariants,
    isMutating: isLoadingPackage,
    isPackageUpgraded: false, // Battery systems don't have the upgrade concept
    mainHardwareType: 'battery_system',
    changePackage,
    changePurchaseModel,
  };
}
